class Solution:
    def subsetXORSum(self, nums):
        from itertools import combinations
        total = 0
        n = len(nums)
        for r in range(n + 1):
            for combo in combinations(nums, r):
                x = 0
                for v in combo:
                    x ^= v
                total += x
        return total

